import base64
from PIL import Image

# Base64 data from browser - SVG rendered at 64x64
b64 = ""

data = base64.b64decode(b64)
with open('C:/qcanary/tmp_svg_render_64.png', 'wb') as f:
    f.write(data)

# Open and downscale to 32x32
img = Image.open('C:/qcanary/tmp_svg_render_64.png').convert('RGBA')
print(f"Browser-rendered SVG: {img.size}")

# Downscale to 32x32 with LANCZOS
favicon = img.resize((32, 32), Image.LANCZOS)
favicon.save('C:/qcanary/apps/web/public/favicon.png')
print("Saved favicon.png (browser-rendered SVG at 32x32)")

# Verify
pixels = list(favicon.getdata())
non_transparent = sum(1 for p in pixels if p[3] > 0)
greenish = sum(1 for p in pixels if p[3] > 0 and p[1] > 100 and p[0] < 50)
print(f"Non-transparent: {non_transparent}, Greenish: {greenish}")
